import React from "react";

export default function FilmLibrarySection({ onOpenDemo }) {
  return (
    <section
      id="film-library"
      style={{
        width: "100%",
        padding: "90px 20px",
        background: "radial-gradient(1200px 600px at 50% 20%, rgba(255,140,0,0.12), rgba(0,0,0,1))",
        borderTop: "1px solid rgba(255,255,255,0.06)",
        borderBottom: "1px solid rgba(255,255,255,0.06)",
      }}
    >
      <div
        style={{
          maxWidth: 1150,
          margin: "0 auto",
          display: "grid",
          gridTemplateColumns: "1.1fr 0.9fr",
          gap: 28,
          alignItems: "center",
        }}
      >
        {/* LEFT */}
        <div>
          <div
            style={{
              display: "inline-flex",
              alignItems: "center",
              gap: 10,
              padding: "8px 12px",
              borderRadius: 999,
              border: "1px solid rgba(255,255,255,0.12)",
              background: "rgba(0,0,0,0.35)",
              color: "rgba(255,255,255,0.85)",
              fontSize: 13,
              letterSpacing: 0.2,
            }}
          >
            <span style={{ width: 8, height: 8, borderRadius: 999, background: "#ff9a2f" }} />
            Film Library (Preview)
          </div>

          <h2
            style={{
              marginTop: 18,
              marginBottom: 12,
              color: "#fff",
              fontSize: 48,
              lineHeight: 1.05,
              fontWeight: 800,
            }}
          >
            Explore films ready for one-time screening
          </h2>

          <p
            style={{
              margin: 0,
              color: "rgba(255,255,255,0.78)",
              fontSize: 18,
              lineHeight: 1.6,
              maxWidth: 620,
            }}
          >
            This section will become your curated film catalog. Later we’ll replace this placeholder
            with the exact design (cards, filters, categories, etc.).
          </p>

          <div style={{ marginTop: 22, display: "flex", gap: 12, flexWrap: "wrap" }}>
            <button
              onClick={onOpenDemo}
              style={{
                cursor: "pointer",
                border: "none",
                borderRadius: 12,
                padding: "12px 18px",
                background: "linear-gradient(180deg, #ffb347, #ff8c00)",
                color: "#1b1207",
                fontWeight: 800,
                fontSize: 16,
                boxShadow: "0 16px 40px rgba(0,0,0,0.45)",
              }}
            >
              ▶ Try Demo Film
            </button>

            <button
              onClick={() => {
                const next = document.getElementById("why-cinegate");
                if (next) next.scrollIntoView({ behavior: "smooth", block: "start" });
              }}
              style={{
                cursor: "pointer",
                borderRadius: 12,
                padding: "12px 18px",
                background: "rgba(255,255,255,0.06)",
                border: "1px solid rgba(255,255,255,0.12)",
                color: "rgba(255,255,255,0.9)",
                fontWeight: 700,
                fontSize: 16,
              }}
            >
              Continue ↓
            </button>
          </div>
        </div>

        {/* RIGHT: placeholder “film cards” */}
        <div
          style={{
            borderRadius: 18,
            border: "1px solid rgba(255,255,255,0.10)",
            background: "rgba(0,0,0,0.35)",
            padding: 18,
            boxShadow: "0 24px 60px rgba(0,0,0,0.55)",
          }}
        >
          <div style={{ display: "grid", gridTemplateColumns: "repeat(2, 1fr)", gap: 12 }}>
            {["CONGO", "NAIROBI", "SETTLERS", "MAKATI"].map((title) => (
              <div
                key={title}
                style={{
                  borderRadius: 14,
                  border: "1px solid rgba(255,255,255,0.10)",
                  background: "rgba(255,255,255,0.04)",
                  padding: 12,
                  minHeight: 120,
                  display: "flex",
                  flexDirection: "column",
                  justifyContent: "space-between",
                }}
              >
                <div style={{ color: "#fff", fontWeight: 800, letterSpacing: 0.4 }}>{title}</div>
                <div style={{ color: "rgba(255,255,255,0.70)", fontSize: 13 }}>
                  One-time screening license
                </div>
              </div>
            ))}
          </div>

          <div style={{ marginTop: 14, color: "rgba(255,255,255,0.65)", fontSize: 13 }}>
            Placeholder cards — we’ll swap these with your real library UI.
          </div>
        </div>
      </div>
    </section>
  );
}
